
# set defaults for platform variables
if [ "$VARIANT" != "" ]; then
    ARCHIVE_FORMAT='tgz'
    JAVA_HOME='/opt/java/jdk8'
    GOROOT='/opt/go1.8/go'
    GOBINDIR='/opt/go1.8/go/bin'
fi

ARCHIVE_CONTENT_TYPE='x-gzip'

# set platform-specific variables
case $VARIANT in
amazon)
    PUSH_ARCH='x86_64-enterprise-amzn64'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
centos6-perf)
    PUSH_ARCH='x86_64-centos6'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
debian81)
    PUSH_ARCH='x86_64-debian81'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
debian92)
    PUSH_ARCH='x86_64-debian92'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
macos)
    PKG_CONFIG_PATH='/usr/local/opt/openssl/lib/pkgconfig'
    PUSH_ARCH='x86_64'
    PUSH_NAME='osx'
    GOROOT='/usr/local/go1.8/go'
    GOBINDIR='/usr/local/go1.8/go/bin'
    BUILD_GSSAPI='true'
    ;;
rhel71-ppc)
    LIBRARY_PATH='/opt/mongodbtoolchain/v2/bin/'
    PUSH_ARCH='ppc64le-rhel71'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
rhel62)
    PUSH_ARCH='x86_64-rhel62'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
rhel67-s390x)
    LIBRARY_PATH='/opt/mongodbtoolchain/v2/bin/'
    PUSH_ARCH='s390x-enterprise-rhel67'
    PUSH_NAME='linux'
    CC='s390x-redhat-linux-gcc'
    BUILD_GSSAPI='true'
    ;;
rhel70)
    PUSH_ARCH='x86_64-rhel70'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
rhel72-s390x)
    LIBRARY_PATH='/opt/mongodbtoolchain/v2/bin/'
    PUSH_ARCH='s390x-enterprise-rhel72'
    PUSH_NAME='linux'
    CC='s390x-redhat-linux-gcc'
    BUILD_GSSAPI='true'
    ;;
suse12)
    PUSH_ARCH='x86_64-suse12'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
ubuntu1404)
    PUSH_ARCH='x86_64-ubuntu-1404'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
ubuntu1604)
    PUSH_ARCH='x86_64-ubuntu-1604'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
ubuntu1604-s390x)
    LIBRARY_PATH='/opt/mongodbtoolchain/v2/bin/'
    PUSH_ARCH='s390x-enterprise-ubuntu-1604'
    PUSH_NAME='linux'
    CC='s390x-mongodb-linux-gcc'
    BUILD_GSSAPI='true'
    ;;
ubuntu1604-ppc)
    LIBRARY_PATH='/opt/mongodbtoolchain/v2/bin/'
    PUSH_ARCH='ppc64le-ubuntu-1604'
    PUSH_NAME='linux'
    BUILD_GSSAPI='true'
    ;;
windows)
    PUSH_ARCH='x86_64'
    PUSH_NAME='win32'
    LIBRARY_PATH='/cygdrive/c/sasl/'
    MINGW_PATH='/cygdrive/c/mingw-w64/x86_64-4.9.1-posix-seh-rt_v3-rev1/mingw64/bin'
    ARCHIVE_FORMAT='zip'
    ARCHIVE_CONTENT_TYPE='zip'
    GOROOT='c:\go1.8\go'
    GOBINDIR='/cygdrive/c/go1.8/go/bin'
    BUILD_GSSAPI='true'
    ;;
*) # local
    BUILD_GSSAPI='true'
esac
